mapper.select:
select MIN(s.Schedule_ID) as scheduleId, GROUP_CONCAT(cl.Class_Name ORDER BY cl.Class_ID SEPARATOR '、') as className, MAX(t.Teacher_Name) as teacherName, MAX(c.Course_Name) as courseName, MAX(cr.Classroom_Name) as classroomName, s.Schedule_Weekday as weekday, s.Schedule_Section as section, s.Schedule_Week as week, MAX(c.Course_SingleHour) as courseSingleHour, MAX(c.Course_StartWeek) as courseStartWeek, MAX(c.Course_EndWeek) as courseEndWeek, s.Schedule_Course_ID as scheduleCourseId, s.Schedule_Classroom_ID as scheduleClassroomId from schedule s left join class cl on s.Schedule_Class_ID = cl.Class_ID left join teacher t on s.Schedule_Teacher_ID = t.Teacher_ID left join course c on s.Schedule_Course_ID = c.Course_ID left join classroom cr on s.Schedule_Classroom_ID = cr.Classroom_ID
and s.Schedule_Week = #{week}
and s.Schedule_Class_ID = #{classId}
and s.Schedule_Teacher_ID = #{teacherId}
and s.Schedule_Classroom_ID = #{classroomId}
group by s.Schedule_Teacher_ID, s.Schedule_Course_ID, s.Schedule_Classroom_ID, s.Schedule_Week, s.Schedule_Weekday, s.Schedule_Section order by s.Schedule_Weekday, s.Schedule_Section, MIN(s.Schedule_ID)

mapper.delete:
delete from schedule
where Schedule_Teacher_ID = #{teacherId}
  and Schedule_Course_ID = #{courseId}
